// ==================== Correção Ortográfica via Claude API ====================

async function corrigirOrtografia(texto) {
  if (!texto || texto.trim().length < 10) return texto;
  try {
    const apiKey = ""; // API key should be in .env file
    if (!apiKey) {
      // debug log removed
      return texto;
    }

    const response = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: { 
        "Content-Type": "application/json",
        "x-api-key": apiKey
      },
      body: JSON.stringify({
        model: "claude-sonnet-4-6",
        max_tokens: 1000,
        messages: [{
          role: "user",
          content: `Corrija APENAS os erros de acentuacao e ortografia do texto abaixo. 
Não altere o conteúdo, o estilo ou a estrutura das frases.
Retorne SOMENTE o texto corrigido, sem explicações, sem aspas, sem prefixos.

Texto: ${texto}`
        }]
      })
    });
    
    if (!response.ok) {
      return texto;
    }
    
    const data = await response.json();
    const corrigido = data?.content?.[0]?.text?.trim();
    return corrigido || texto;
  } catch (e) {
    // debug log removed
    return texto; // em caso de erro, retorna o texto original
  }
}

function useCorrecaoOrtografica(value, onChange) {
  const [corrigindo, setCorrigindo] = useState(false);
  const [corrigido, setCorrigido] = useState(false);
  const timeoutRef = useRef(null);

  const handleBlur = async () => {
    if (!value || value.trim().length < 10 || corrigindo) return;
    
    // Limpar timeout anterior para evitar múltiplas chamadas
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
    
    // Debounce: esperar 800ms antes de chamar a API
    timeoutRef.current = setTimeout(async () => {
      setCorrigindo(true);
      setCorrigido(false);
      try {
        const novo = await corrigirOrtografia(value);
        if (novo !== value) {
          onChange(novo);
          setCorrigido(true);
          setTimeout(() => setCorrigido(false), 2500);
        }
      } finally {
        setCorrigindo(false);
      }
    }, 800);
  };

  // Cleanup ao desmontar
  useEffect(() => {
    return () => {
      if (timeoutRef.current) {
        clearTimeout(timeoutRef.current);
        timeoutRef.current = null;
      }
    };
  }, []);

  return { handleBlur, corrigindo, corrigido };
}


// ── Hook de salvamento com feedback ──────────────────────────────────────────
function useSalvarSecao(chave, dados) {
  const [status, setStatus] = useState("idle"); // idle | salvando | salvo | erro

  const salvar = async (onDepois) => {
    setStatus("salvando");
    try {
      // Serializar com fallback seguro
      const payload = JSON.stringify({ dados: dados ?? {}, ts: Date.now() });
      // localStorage pode não estar disponível fora do artifact — usar fallback local
      if (localStorage.setItem) {
        localStorage.setItem(chave, payload);
      } else {
        // fallback: sessionStorage (com persistência limitada)
        try { 
          sessionStorage.setItem(chave, payload);
          // debug log removed
        } catch (sessionError) {
          throw new Error("Falha ao salvar em sessionStorage: " + sessionError.message);
        }
      }
      setStatus("salvo");
      const t1 = setTimeout(() => {
        setStatus("idle");
        onDepois?.();
      }, 1200);
      return () => clearTimeout(t1);
    } catch (e) {
      // debug log removed
      // NÃO fingir que salvou - mostrar erro ao usuário
      setStatus("erro");
      const t2 = setTimeout(() => {
        setStatus("idle");
        // Chamar onDepois mesmo com erro para permitir retry
        onDepois?.();
      }, 3000);
      return () => clearTimeout(t2);
    }
  };

  return { status, salvar };
}

function BotaoSalvar({ status, onClick, label = "Salvar e voltar", faltando = [] }) {
  const [tentouSalvar, setTentouSalvar] = useState(false);

  const cor = status === "salvo" ? "#2E7D4F"
    : status === "erro" ? "#C0392B"
    : "#0A2647";

  const texto = status === "salvando" ? "Salvando..."
    : status === "salvo" ? "✓ Salvo!"
    : status === "erro" ? "Erro ao salvar"
    : label;

  const handleClick = () => {
    setTentouSalvar(true);
    onClick();
  };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", gap: 6 }}>
      {tentouSalvar && faltando.length > 0 && status !== "salvo" && (
        <div style={{
          background: "#FBF3DC", border: "1px solid #E0B84B",
          borderRadius: 8, padding: "8px 12px",
          fontSize: 12, color: "#7A5C00", lineHeight: 1.5,
        }}>
          <strong>Campos recomendados não preenchidos:</strong>
          <ul style={{ margin: "4px 0 0 14px", padding: 0 }}>
            {faltando.map((item, i) => <li key={i}>{item}</li>)}
          </ul>
        </div>
      )}
      <button
        onClick={handleClick}
        disabled={status === "salvando"}
        style={{
          background: cor, color: "#fff",
          border: "none", borderRadius: 12, padding: "15px",
          fontSize: 15, fontWeight: 700, fontFamily: "Inter, sans-serif",
          cursor: status === "salvando" ? "not-allowed" : "pointer",
          boxShadow: `0 4px 12px ${cor}44`,
          transition: "background 0.2s",
          display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
        }}
      >
        {texto}
      </button>
    </div>
  );
}


// ── Validação de campos por seção ────────────────────────────────────────────
function validarDadosGerais(dados) {
  const faltando = [];
  
  // ✅ ADICIONADO: Validações com fallbacks seguros
  if (!dados) {
    // debug log removed
    return ["Dados gerais não carregados"];
  }
  
  if (!dados?.empresa?.razaoSocial?.trim()) faltando.push("Razão Social da empresa");
  if (!dados?.empresa?.cnpj?.trim()) faltando.push("CNPJ da empresa");
  if (!dados?.contrato?.identificacao?.trim()) faltando.push("Identificação do contrato");
  if (!dados?.contrato?.contratante?.trim()) faltando.push("Contratante");
  if (!dados?.responsavel?.nome?.trim()) faltando.push("Nome do responsável técnico");
  if (!dados?.responsavel?.crefito?.trim()) faltando.push("CREFITO do responsável técnico");
  
  // ✅ ADICIONADO: Log de validação em desenvolvimento
  if (faltando.length > 0) {
    console.warn("⚠️ Validação DadosGerais encontrou campos faltando:", faltando);
  }
  
  return faltando;
}

function validarPopulacao(dados) {
  const faltando = [];
  
  // ✅ ADICIONADO: Fallback seguro
  if (!dados) {
    // debug log removed
    return ["Dados de população não carregados"];
  }
  
  const total = Number(dados?.totalMasculino || 0) + Number(dados?.totalFeminino || 0);
  if (total === 0) faltando.push("Total de trabalhadores (masculino ou feminino)");
  
  const temEscolaridade = (dados?.escolaridade || []).some(e => Number(e.valor) > 0);
  if (!temEscolaridade) faltando.push("Dados de escolaridade");
  
  const temQueixas = (dados?.queixas || []).some(e => Number(e.valor) > 0);
  if (!temQueixas) faltando.push("Dados de queixas musculoesqueléticas");
  
  // ✅ ADICIONADO: Log de validação
  if (faltando.length > 0) {
    console.warn("⚠️ Validação População encontrou campos faltando:", faltando);
  }
  
  return faltando;
}

function validarPlanoAcao(dados) {
  const faltando = [];
  
  // ✅ ADICIONADO: Fallback seguro
  if (!dados) {
    // debug log removed
    return ["Dados de plano de ação não carregados"];
  }
  
  if (!dados?.acoes?.length) faltando.push("Pelo menos uma ação no plano");
  if (!dados?.consideracoes?.trim()) faltando.push("Considerações finais");
  
  // ✅ ADICIONADO: Log de validação
  if (faltando.length > 0) {
    console.warn("⚠️ Validação PlanoAcao encontrou campos faltando:", faltando);
  }
  
  return faltando;
}

function validarAnexos(dados) {
  const faltando = [];
  
  // ✅ ADICIONADO: Fallback seguro
  if (!dados) {
    // debug log removed
    return ["Dados de anexos não carregados"];
  }
  
  if (!dados?.certificado) faltando.push("Certificado de capacitação do responsável técnico (Anexo 4)");
  
  // ✅ ADICIONADO: Log de validação
  if (faltando.length > 0) {
    console.warn("⚠️ Validação Anexos encontrou campos faltando:", faltando);
  }
  
  return faltando;
}

function validarCargo(cargo) {
  const faltando = [];
  if (!cargo?.nome?.trim()) faltando.push("Nome do cargo");
  if (!cargo?.condicoes?.descricaoFuncao?.trim()) faltando.push("Descrição das funções");
  if (!cargo?.condicoes?.jornada?.trim()) faltando.push("Jornada de trabalho");
  const temRisco = Object.values(cargo?.riscos || {}).some(v => v?.trim());
  if (!temRisco) faltando.push("Pelo menos um risco ergonômico identificado");
  if (!cargo?.rula?.finalD && !cargo?.rula?.finalE) faltando.push("Resultado final do RULA");
  if (!cargo?.conclusao?.trim()) faltando.push("Conclusão do cargo");
  return faltando;
}

