// ==================== CargoList ====================
// ---------- Swipeable card ----------

function CargoCard({ cargo, onOpen, onDelete, onToggleComplete }) {
  const [dragX, setDragX] = useState(0);
  const [dragging, setDragging] = useState(false);
  const startX = useRef(0);
  const REVEAL = 76; // px revealed for the delete action

  const handleStart = (clientX) => {
    startX.current = clientX;
    setDragging(true);
  };

  const handleMove = (clientX) => {
    if (!dragging) return;
    const delta = clientX - startX.current;
    const next = Math.min(0, Math.max(delta, -REVEAL - 20));
    setDragX(next);
  };

  const handleEnd = () => {
    setDragging(false);
    setDragX((x) => (x < -REVEAL / 2 ? -REVEAL : 0));
  };

  return (
    <div className="card-wrap">
      <button
        className="card-delete"
        onClick={() => onDelete(cargo.id)}
        aria-label={`Excluir ${cargo.nome}`}
        style={{ opacity: dragX < -10 ? 1 : 0 }}
      >
        <Trash2 size={18} />
      </button>
      <div
        className="card"
        style={{ transform: `translateX(${dragX}px)` }}
        onTouchStart={(e) => handleStart(e.touches[0].clientX)}
        onTouchMove={(e) => handleMove(e.touches[0].clientX)}
        onTouchEnd={handleEnd}
        onMouseDown={(e) => handleStart(e.clientX)}
        onMouseMove={(e) => dragging && handleMove(e.clientX)}
        onMouseUp={handleEnd}
        onMouseLeave={() => dragging && handleEnd()}
        onClick={() => dragX === 0 && onOpen(cargo.id)}
      >
        <span className="card-name">{cargo.nome || "Cargo sem nome"}</span>
        <button
          className={`card-status ${cargo.complete ? "is-complete" : ""}`}
          onClick={(e) => {
            e.stopPropagation();
            onToggleComplete(cargo.id);
          }}
          aria-label={cargo.complete ? "Marcar como incompleto" : "Marcar como completo"}
          aria-pressed={cargo.complete}
        >
          {cargo.complete ? <Check size={13} strokeWidth={3} /> : null}
        </button>
      </div>
    </div>
  );
}

