// ---------- Input masks ----------
// These format the value as the person types, matching the patterns used
// in the reference document (e.g. CNPJ 00.000.000/0000-00, CNAE 00.00-0-00).

function maskCNPJ(raw) {
  const digits = raw.replace(/\D/g, "").slice(0, 14);
  let out = digits;
  if (digits.length > 2) out = `${digits.slice(0, 2)}.${digits.slice(2)}`;
  if (digits.length > 5) out = `${out.slice(0, 6)}.${digits.slice(5)}`;
  if (digits.length > 8) out = `${out.slice(0, 10)}/${digits.slice(8)}`;
  if (digits.length > 12) out = `${out.slice(0, 15)}-${digits.slice(12)}`;
  return out;
}

function maskCNAE(raw) {
  const digits = raw.replace(/\D/g, "").slice(0, 7);
  let out = digits;
  if (digits.length > 2) out = `${digits.slice(0, 2)}.${digits.slice(2)}`;
  if (digits.length > 4) out = `${out.slice(0, 5)}-${digits.slice(4)}`;
  if (digits.length > 5) out = `${out.slice(0, 7)}-${digits.slice(5)}`;
  return out;
}

function maskCREFITO(raw) {
  // Aceita: XXXXXX-F (Fisioterapeuta) ou XXXXXX-TO (Terapeuta Ocupacional)
  const upper = raw.toUpperCase().replace(/[^0-9A-Z\-]/g, "");
  // Extrai apenas dígitos (até 6)
  const digits = upper.replace(/[^0-9]/g, "").slice(0, 6);
  // Extrai letras após o hífen
  const afterDash = upper.includes("-") ? upper.split("-").slice(1).join("") : upper.replace(/[0-9]/g, "");
  const letters = afterDash.replace(/[^A-Z]/g, "").slice(0, 2); // máx TO = 2 letras
  if (!digits) return "";
  if (!letters) return upper.includes("-") ? `${digits}-` : digits;
  return `${digits}-${letters}`;
}

function validarCREFITO(valor) {
  if (!valor || valor.trim() === "") return null; // vazio = neutro
  const match = valor.trim().match(/^(\d{4,6})-(F|TO)$/);
  if (!match) return false;
  return true;
}

const MASKS = { cnpj: maskCNPJ, cnae: maskCNAE, crefito: maskCREFITO };

// ---------- Small UI helpers ----------

function CREFITOField({ label, value, onChange, placeholder }) {
  const valido = validarCREFITO(value);
  const numero = value ? value.replace(/[^0-9]/g, "") : "";
  const urlCoffito = numero
    ? `https://coffito.gov.br/nsite/?page_id=2338&numero=${numero}`
    : "https://coffito.gov.br/nsite/?page_id=2338";

  return (
    <div className="field">
      <span className="field-label">{label}</span>
      <div style={{ position: "relative" }}>
        <input
          className="field-input"
          value={value}
          onChange={(e) => onChange(maskCREFITO(e.target.value))}
          placeholder={placeholder || "Ex.: 123456-F ou 123456-TO"}
          style={{
            paddingRight: 44,
            borderColor: valido === false ? "#C0392B" : valido === true ? "#2E7D4F" : undefined,
            background: valido === false ? "#FBE8E6" : valido === true ? "#F0FAF4" : undefined,
          }}
          inputMode="text"
          autoCapitalize="characters"
        />
        {valido !== null && (
          <span style={{
            position: "absolute", right: 12, top: "50%", transform: "translateY(-50%)",
            fontSize: 16, pointerEvents: "none",
          }}>
            {valido ? <Check size={15} strokeWidth={3} /> : <X size={15} strokeWidth={3} />}
          </span>
        )}
      </div>
      {valido === false && (
        <span className="field-hint" style={{ color: "#C0392B" }}>
          Formato invalido. Use: 123456-F (Fisioterapeuta) ou 123456-TO (Terapeuta Ocupacional)
        </span>
      )}
      {valido === true && (
        <span className="field-hint" style={{ color: "#2E7D4F" }}>
          Formato valido.{" "}
          <a
            href={urlCoffito}
            target="_blank"
            rel="noopener noreferrer"
            style={{ color: "#2E7D4F", fontWeight: 700, textDecoration: "underline" }}
          >
            Verificar no COFFITO ↗
          </a>
        </span>
      )}
      {valido === null && (
        <span className="field-hint">
          Formato: 123456-F (Fisioterapeuta) ou 123456-TO (Terapeuta Ocupacional)
        </span>
      )}
    </div>
  );
}

function DadosGerais_Field({ label, value, onChange, placeholder, multiline, mask, hint, autoCorrigir }) {
  const maskFn = mask ? MASKS[mask] : null;
  const handleChange = (raw) => onChange(maskFn ? maskFn(raw) : raw);
  const deveCorigir = !!(multiline && autoCorrigir);
  const { handleBlur, corrigindo, corrigido } = useCorrecaoOrtografica(
    deveCorigir ? value : "",
    deveCorigir ? onChange : () => {}
  );

  return (
    <label className="field">
      <span className="field-label" style={{ display: "flex", alignItems: "center", gap: 6 }}>
        {label}
        {corrigindo && <span style={{ fontSize: 10, color: "#9B9A90", fontWeight: 400 }}>corrigindo...</span>}
        {corrigido && <span style={{ fontSize: 10, color: "#2E7D4F", fontWeight: 600 }}>✓ corrigido</span>}
      </span>
      {multiline ? (
        <textarea
          className="field-input field-textarea"
          value={value}
          onChange={(e) => handleChange(e.target.value)}
          onBlur={deveCorigir ? handleBlur : undefined}
          placeholder={placeholder}
          rows={3}
        />
      ) : (
        <input
          className="field-input"
          value={value}
          onChange={(e) => handleChange(e.target.value)}
          placeholder={placeholder}
          inputMode={mask === "cnpj" || mask === "cnae" ? "numeric" : undefined}
        />
      )}
      {hint && <span className="field-hint">{hint}</span>}
    </label>
  );
}

function ImageUploadField({ label, hint, value, onChange }) {
  const handleFile = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => onChange(reader.result);
    reader.readAsDataURL(file);
    e.target.value = "";
  };

  return (
    <div className="image-upload-field">
      <span className="field-label">{label}</span>
      {hint && <span className="upload-hint">{hint}</span>}
      {value ? (
        <div className="image-preview">
          <img src={value} alt={label} />
          <button className="image-remove-btn" onClick={() => onChange(null)}>
            Remover
          </button>
        </div>
      ) : (
        <div className="native-file-wrap">
          <input type="file" accept="image/*" onChange={handleFile} className="native-file-input" />
        </div>
      )}
    </div>
  );
}

function TextoTeoricoField({ label, value, onChange, original }) {
  const foiEditado = value !== original;
  return (
    <div className="texto-field">
      <div className="texto-field-head">
        <span className="field-label">{label}</span>
        {foiEditado && <span className="edited-tag">Editado</span>}
      </div>
      <textarea
        className="field-input field-textarea texto-textarea"
        value={value}
        onChange={(e) => onChange(e.target.value)}
        rows={8}
      />
      {foiEditado && (
        <button className="restore-btn" onClick={() => onChange(original)}>
          Restaurar texto original
        </button>
      )}
    </div>
  );
}

function DadosGerais_SectionShell({ title, subtitle, accent, complete, open, onToggle, children }) {
  return (
    <section className="section" style={{ "--accent": accent || "#0A2647" }}>
      <button className="section-head" onClick={onToggle} aria-expanded={open}>
        <span className="section-tab" />
        <span className="section-head-text">
          <span className="section-title">{title}</span>
          {subtitle && <span className="section-subtitle">{subtitle}</span>}
        </span>
        <span className={`section-status ${complete ? "is-complete" : ""}`}>
          {complete ? <Check size={14} strokeWidth={3} /> : null}
        </span>
        {open ? <ChevronUp size={18} className="chev" /> : <ChevronDown size={18} className="chev" />}
      </button>
      {open && <div className="section-body">{children}</div>}
    </section>
  );
}

