// ---------- Small UI helpers ----------

function NumberRow({ label, value, onChange }) {
  return (
    <div className="num-row">
      <span className="num-row-label">{label}</span>
      <input
        className="num-row-input"
        value={value}
        onChange={(e) => onChange(e.target.value.replace(/[^0-9]/g, ""))}
        inputMode="numeric"
        placeholder="0"
      />
    </div>
  );
}

function SimNaoRow({ simLabel = "Sim", naoLabel = "Não", sim, nao, onChangeSim, onChangeNao }) {
  return (
    <div className="simnao-row">
      <NumberRow label={simLabel} value={sim} onChange={onChangeSim} />
      <NumberRow label={naoLabel} value={nao} onChange={onChangeNao} />
    </div>
  );
}

function MiniPie({ data }) {
  const chartData = data.map((d) => ({ ...d, valor: Number(d.valor) || 0 }));
  const hasData = chartData.some((d) => d.valor > 0);
  if (!hasData) {
    return <p className="chart-empty">Preencha os numeros para ver o gráfico</p>;
  }
  return (
    <ResponsiveContainer width="100%" height={220}>
      <PieChart>
        <Pie
          data={chartData}
          dataKey="valor"
          nameKey="label"
          cx="50%"
          cy="50%"
          outerRadius={80}
          label={({ percent }) => `${(percent * 100).toFixed(0)}%`}
        >
          {chartData.map((_, i) => (
            <Cell key={i} fill={PALETTE[i % PALETTE.length]} />
          ))}
        </Pie>
        <Legend
          layout="vertical"
          align="right"
          verticalAlign="middle"
          wrapperStyle={{ fontSize: 11, fontFamily: "Inter, sans-serif" }}
        />
        <Tooltip />
      </PieChart>
    </ResponsiveContainer>
  );
}

function MiniBar({ data, horizontal }) {
  const chartData = data.map((d) => ({ ...d, valor: Number(d.valor) || 0 }));
  const hasData = chartData.some((d) => d.valor > 0);
  if (!hasData) {
    return <p className="chart-empty">Preencha os numeros para ver o gráfico</p>;
  }
  return (
    <ResponsiveContainer width="100%" height={Math.max(180, chartData.length * 38)}>
      <BarChart data={chartData} layout={horizontal ? "vertical" : "horizontal"} margin={{ left: 8, right: 16 }}>
        <CartesianGrid strokeDasharray="3 3" stroke="#E5E3DC" />
        {horizontal ? (
          <>
            <XAxis type="number" tick={{ fontSize: 11, fontFamily: "Inter, sans-serif" }} />
            <YAxis
              type="category"
              dataKey="label"
              width={130}
              tick={{ fontSize: 11, fontFamily: "Inter, sans-serif" }}
            />
          </>
        ) : (
          <>
            <XAxis dataKey="label" tick={{ fontSize: 10, fontFamily: "Inter, sans-serif" }} interval={0} angle={-15} textAnchor="end" height={50} />
            <YAxis tick={{ fontSize: 11, fontFamily: "Inter, sans-serif" }} />
          </>
        )}
        <Tooltip />
        <Bar dataKey="valor" radius={[4, 4, 4, 4]}>
          {chartData.map((_, i) => (
            <Cell key={i} fill={PALETTE[i % PALETTE.length]} />
          ))}
        </Bar>
      </BarChart>
    </ResponsiveContainer>
  );
}

function DadosPopulacao_SectionShell({ title, subtitle, accent, open, onToggle, children }) {
  return (
    <section className="section" style={{ "--accent": accent || "#0A2647" }}>
      <button className="section-head" onClick={onToggle} aria-expanded={open}>
        <span className="section-tab" />
        <span className="section-head-text">
          <span className="section-title">{title}</span>
          {subtitle && <span className="section-subtitle">{subtitle}</span>}
        </span>
        {open ? <ChevronUp size={18} className="chev" /> : <ChevronDown size={18} className="chev" />}
      </button>
      {open && <div className="section-body">{children}</div>}
    </section>
  );
}

