// ---------- Default closing text, extracted from the reference AET document ----------

const TEXTO_CONSIDERACOES = `É importante destacar que a Análise Ergonômica do Trabalho é a primeira fase do programa, que contempla os riscos ergonômicos. As medidas de controle propostas são necessárias para prevenção de riscos ergonômicos e deverão ser monitoradas após a implementacao das acoes.

De acordo com a NR 01 (SEPRT, 2019), a avaliacao de riscos deve constituir um processo contínuo e ser revista a cada dois anos ou quando da ocorrência das seguintes situações:

a) pós implementacao das medidas de prevenção, para avaliacao de riscos residuais;
b) após inovações e modificações nas tecnologias, ambientes, processos, condições, procedimentos e organizacao do trabalho que impliquem em novos riscos ou modifiquem os riscos existentes;
c) quando identificadas inadequações, insuficiências ou ineficácias das medidas de prevenção;
d) na ocorrência de acidentes ou doenças relacionadas ao trabalho;
e) quando houver mudança nos requisitos legais aplicáveis.

Com isso, esta AET deverá ser revisada sempre que houver a inserção de novas funções e/ou adequações diversas no ambiente de trabalho, como mudanças de layout, aquisição de novas ferramentas, mobiliários ou outros aspectos relacionados aos cinco grandes grupos da Ergonomia, além das situações apresentadas acima e, caso nenhum desses aspectos se altere, a validade desta AET será de 2 (dois) anos.`;

const PRIORIDADES = [
  { key: "alta", label: "Alta", color: "#C0392B", bg: "#FBE8E6" },
  { key: "media", label: "Média", color: "#B8860B", bg: "#FBF3DC" },
  { key: "baixa", label: "Baixa", color: "#2E7D4F", bg: "#E8F5EC" },
];

const emptyAcao = () => ({
  id: crypto.randomUUID(),
  prioridade: "media",
  oQue: "",
  porQue: "",
  quem: "",
  como: "",
  onde: "",
  quando: "",
});

// ---------- Small UI helpers ----------

function PlanoAcao_Field({ label, value, onChange, placeholder, multiline }) {
  return (
    <label className="field">
      <span className="field-label">{label}</span>
      {multiline ? (
        <textarea
          className="field-input field-textarea"
          value={value}
          onChange={(e) => onChange(e.target.value)}
          placeholder={placeholder}
          rows={2}
        />
      ) : (
        <input
          className="field-input"
          value={value}
          onChange={(e) => onChange(e.target.value)}
          placeholder={placeholder}
        />
      )}
    </label>
  );
}

function PrioridadeSelector({ value, onChange }) {
  return (
    <div className="prio-selector">
      {PRIORIDADES.map((p) => (
        <button
          key={p.key}
          className={`prio-chip ${value === p.key ? "is-active" : ""}`}
          style={{
            background: value === p.key ? p.bg : "#fff",
            color: value === p.key ? p.color : "#9B9A90",
            borderColor: value === p.key ? p.color : "#E5E3DC",
          }}
          onClick={() => onChange(p.key)}
          aria-pressed={value === p.key}
        >
          <span className="prio-dot" style={{ background: p.color }} />
          {p.label}
        </button>
      ))}
    </div>
  );
}

function AcaoCard({ acao, index, onUpdate, onDelete }) {
  const [open, setOpen] = useState(true);
  const prio = PRIORIDADES.find((p) => p.key === acao.prioridade);

  return (
    <div className="acao-card" style={{ "--prio-color": prio.color }}>
      <button className="acao-head" onClick={() => setOpen((o) => !o)} aria-expanded={open}>
        <span className="acao-tab" />
        <span className="acao-head-text">
          <span className="acao-number">Ação {index + 1}</span>
          <span className="acao-title">{acao.oQue || "Sem descrição ainda"}</span>
        </span>
        {open ? <ChevronUp size={18} className="chev" /> : <ChevronDown size={18} className="chev" />}
      </button>

      {open && (
        <div className="acao-body">
          <span className="field-label">Prioridade de risco (PR)</span>
          <PrioridadeSelector
            value={acao.prioridade}
            onChange={(v) => onUpdate({ ...acao, prioridade: v })}
          />

          <PlanoAcao_Field
            label="O quê (acao proposta)"
            value={acao.oQue}
            onChange={(v) => onUpdate({ ...acao, oQue: v })}
            placeholder="Ex: Adquirir suporte de notebook"
            multiline
          />
          <PlanoAcao_Field
            label="Por quê (justificativa)"
            value={acao.porQue}
            onChange={(v) => onUpdate({ ...acao, porQue: v })}
            placeholder="Ex: Permite ao trabalhador melhorar a postura"
            multiline
          />
          <PlanoAcao_Field
            label="Quem (responsável)"
            value={acao.quem}
            onChange={(v) => onUpdate({ ...acao, quem: v })}
            placeholder="Ex: Administracao / SESMET"
          />
          <PlanoAcao_Field
            label="Como"
            value={acao.como}
            onChange={(v) => onUpdate({ ...acao, como: v })}
            placeholder="Ex: Realizando aquisição de suporte para notebook"
            multiline
          />
          <PlanoAcao_Field
            label="Onde"
            value={acao.onde}
            onChange={(v) => onUpdate({ ...acao, onde: v })}
            placeholder="Ex.: Funções: Apropriador de Custos, Assistente de RH..."
            multiline
          />
          <PlanoAcao_Field
            label="Quando (prazo)"
            value={acao.quando}
            onChange={(v) => onUpdate({ ...acao, quando: v })}
            placeholder="Ex: Junho 2024 / Agosto 2024"
          />

          <button className="delete-acao-btn" onClick={onDelete}>
            <Trash2 size={14} /> Remover esta acao
          </button>
        </div>
      )}
    </div>
  );
}

function PlanoAcao_SectionShell({ title, subtitle, accent, open, onToggle, children }) {
  return (
    <section className="section" style={{ "--accent": accent || "#0A2647" }}>
      <button className="section-head" onClick={onToggle} aria-expanded={open}>
        <span className="section-tab" />
        <span className="section-head-text">
          <span className="section-title">{title}</span>
          {subtitle && <span className="section-subtitle">{subtitle}</span>}
        </span>
        {open ? <ChevronUp size={18} className="chev" /> : <ChevronDown size={18} className="chev" />}
      </button>
      {open && <div className="section-body">{children}</div>}
    </section>
  );
}

