// ==================== Histórico ====================
// ---------- Commission rule, applied only in the Admin view ----------
// 3% of the declared service value, capped at R$ 50 per laudo — informational
// only, never charged automatically by the app.

const COMISSAO_PERCENTUAL = 0.03;
const COMISSAO_TETO = 50;

function calcularComissao(valor) {
  const num = Number(valor) || 0;
  if (num <= 0) return 0;
  return Math.min(num * COMISSAO_PERCENTUAL, COMISSAO_TETO);
}

function formatBRL(valor) {
  return `R$ ${Number(valor).toFixed(2).replace(".", ",")}`;
}

