// ---------- Main Histórico screen ----------
// `isAdmin` toggles between the personal view (own laudos only) and the
// admin view (everyone's laudos, with the commission reference column).

function Historico({ onClose, registros = [], isAdmin = false }) {
  const [ultimaVisita, setUltimaVisita] = useState(null);

  useEffect(() => {
    (async () => {
      try {
        const result = (() => { const v = localStorage.getItem("admin-ultima-visita-histórico"); return v ? { value: v } : null })();
        if (result?.value) setUltimaVisita(result.value);
      } catch {
        // First time opening — no previous visit recorded yet.
      }
      if (isAdmin) {
        const agora = new Date().toISOString();
        try {
          localStorage.setItem("admin-ultima-visita-histórico", agora);
        } catch {
          // Best-effort; badge will just recompute next time.
        }
      }
    })();
  }, [isAdmin]);

  const novosDesdeUltimaVisita = isAdmin && ultimaVisita
    ? (registros || []).filter((r) => new Date(r.data) > new Date(ultimaVisita)).length
    : 0;

  const registrosOrdenados = [...registros].sort((a, b) => new Date(b.data) - new Date(a.data));

  return (
    <div className="page">
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Sora:wght@500;600;700&family=Inter:wght@400;500;600;700&display=swap');

        * { box-sizing: border-box; }

        .page {
          min-height: 100vh;
          background: #F7F8FA;
          font-family: 'Inter', sans-serif;
          color: #1C1F1D;
          padding-bottom: 40px;
        }

        .topbar {
          background: #0A2647;
          color: #F7F8FA;
          padding: 18px 20px 20px;
          position: sticky;
          top: 0;
          z-index: 20;
        }
        .topbar-row {
          display: flex;
          align-items: center;
          gap: 10px;
          margin-bottom: 4px;
        }
        .back-btn {
          background: none;
          border: none;
          color: #F7F8FA;
          display: flex;
          align-items: center;
          justify-content: center;
          padding: 2px;
          margin-left: -4px;
          cursor: pointer;
          opacity: 0.85;
        }
        .topbar-eyebrow {
          font-family: 'Sora', sans-serif;
          font-size: 11px;
          letter-spacing: 0.08em;
          text-transform: uppercase;
          opacity: 0.7;
          margin: 0;
          display: flex;
          align-items: center;
          gap: 6px;
        }
        .admin-tag {
          background: #E0954F;
          color: #1C1F1D;
          font-size: 9.5px;
          font-weight: 700;
          padding: 2px 7px;
          border-radius: 4px;
          letter-spacing: 0.02em;
        }
        .topbar-title {
          font-size: 22px;
          font-weight: 700;
          margin: 0;
        }

        .content {
          max-width: 640px;
          margin: 0 auto;
          padding: 16px;
        }

        .badge-banner {
          display: flex;
          align-items: center;
          gap: 10px;
          background: #FCF1E6;
          border: 1px solid #E0954F;
          border-radius: 10px;
          padding: 12px 14px;
          margin-bottom: 16px;
        }
        .badge-banner svg { color: #D17A2F; flex-shrink: 0; }
        .badge-banner-text {
          font-size: 13px;
          color: #7A4E1F;
          font-weight: 600;
        }

        .registro-card {
          background: #fff;
          border: 1px solid #E5E3DC;
          border-radius: 10px;
          padding: 14px 16px;
          margin-bottom: 10px;
        }
        .registro-head {
          display: flex;
          align-items: flex-start;
          justify-content: space-between;
          gap: 10px;
          margin-bottom: 6px;
        }
        .registro-empresa {
          font-size: 14.5px;
          font-weight: 700;
          color: #1C1F1D;
        }
        .registro-data {
          font-family: 'Sora', sans-serif;
          font-size: 11px;
          color: #9B9A90;
          white-space: nowrap;
        }
        .registro-profissional {
          font-size: 12.5px;
          color: #8A8A82;
          margin: 0 0 8px;
        }
        .registro-footer {
          display: flex;
          align-items: center;
          justify-content: space-between;
          gap: 10px;
          padding-top: 8px;
          border-top: 1px solid #F0EEE6;
        }
        .registro-arquivo-btn {
          display: flex;
          align-items: center;
          gap: 6px;
          background: none;
          border: none;
          color: #0A2647;
          font-size: 12.5px;
          font-weight: 600;
          cursor: pointer;
          padding: 0;
        }
        .registro-comissao {
          font-family: 'Sora', sans-serif;
          font-size: 12px;
          font-weight: 700;
          color: #E0954F;
        }
        .registro-valor {
          font-size: 12px;
          color: #9B9A90;
        }

        .empty-historico {
          text-align: center;
          padding: 60px 20px;
          color: #9B9A90;
        }
        .empty-historico svg { margin-bottom: 12px; opacity: 0.4; }
        .empty-historico p { font-size: 14px; margin: 0; line-height: 1.5; }

        .admin-note {
          font-size: 12px;
          color: #8A8A82;
          line-height: 1.5;
          margin: 0 0 16px;
          padding: 10px 12px;
          background: #F4F3EE;
          border-radius: 7px;
        }
      `}</style>

      <div className="topbar">
        <div className="topbar-row">
          <button className="back-btn" onClick={onClose} aria-label="Voltar">
            <ArrowLeft size={19} />
          </button>
          <p className="topbar-eyebrow">
            {isAdmin ? "Visão administrativa" : "ErgoLaudo"}
            {isAdmin && <span className="admin-tag">ADMIN</span>}
          </p>
        </div>
        <h1 className="topbar-title">{isAdmin ? "Todos os laudos gerados" : "Meus laudos gerados"}</h1>
      </div>

      <div className="content">
        {isAdmin && novosDesdeUltimaVisita > 0 && (
          <div className="badge-banner">
            <Bell size={18} />
            <span className="badge-banner-text">
              {novosDesdeUltimaVisita} laudo{novosDesdeUltimaVisita === 1 ? "" : "s"} gerado{novosDesdeUltimaVisita === 1 ? "" : "s"} desde sua última visita
            </span>
          </div>
        )}

        {isAdmin && (
          <p className="admin-note">
            A comissão exibida é apenas referência (3% do valor informado, com teto de R$ 50 por laudo) — não há cobrança automática. O acerto é feito conforme o contrato com cada profissional.
          </p>
        )}

        {registrosOrdenados.length === 0 ? (
          <div className="empty-histórico">
            <FileText size={32} />
            <p>Nenhum laudo gerado ainda.</p>
          </div>
        ) : (
          registrosOrdenados.map((reg) => {
            const comissao = calcularComissao(reg.valorCobrado);
            return (
              <div className="registro-card" key={reg.id}>
                <div className="registro-head">
                  <span className="registro-empresa">{reg.empresaNome || "Empresa sem nome"}</span>
                  <span className="registro-data">
                    {new Date(reg.data).toLocaleDateString("pt-BR")}
                  </span>
                </div>
                {isAdmin && (
                  <p className="registro-profissional">Gerado por {reg.profissionalNome || reg.profissionalEmail}</p>
                )}
                <div className="registro-footer">
                  <button className="registro-arquivo-btn" onClick={() => reg.onAbrirArquivo?.()}>
                    <FileText size={14} /> Ver arquivo
                  </button>
                  {isAdmin && Number(reg.valorCobrado) > 0 && (
                    <span>
                      <span className="registro-valor">{formatBRL(reg.valorCobrado)} · </span>
                      <span className="registro-comissao">{formatBRL(comissao)}</span>
                    </span>
                  )}
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
}


