function TelaSplash({ onContinuar, cor = "#0A2647" }) {
  const [saindo, setSaindo] = useState(false);

  const handleContinuar = () => {
    setSaindo(true);
    setTimeout(onContinuar, 400);
  };

  return (
    <div style={{
      minHeight: "100vh",
      background: `linear-gradient(170deg, ${cor} 0%, ${cor}E8 60%, #1A3A5C 100%)`,
      fontFamily: "Inter, sans-serif",
      display: "flex", flexDirection: "column",
      alignItems: "center", justifyContent: "center",
      padding: "40px 32px",
      opacity: saindo ? 0 : 1,
      transition: "opacity 0.4s ease",
    }}>

      {/* Logo */}
      <div style={{
        background: "#fff",
        borderRadius: 28,
        padding: "28px 36px",
        marginBottom: 36,
        boxShadow: "0 20px 60px rgba(0,0,0,0.25)",
        maxWidth: 280, width: "100%",
        display: "flex", alignItems: "center", justifyContent: "center",
      }}>
        <img
          src={LOGO_ERGOLAUDO}
          alt="ErgoLaudo"
          style={{ width: "100%", maxWidth: 220, height: "auto" }}
        />
      </div>

      {/* Texto de boas-vindas */}
      <h1 style={{
        fontFamily: "Sora, sans-serif",
        fontSize: 28, fontWeight: 700,
        color: "#fff", textAlign: "center",
        margin: "0 0 14px", lineHeight: 1.25,
      }}>
        Bem-vindo ao<br />ErgoLaudo
      </h1>
      <p style={{
        fontSize: 15.5, color: "rgba(255,255,255,0.82)",
        textAlign: "center", lineHeight: 1.6,
        margin: "0 0 48px", maxWidth: 300,
      }}>
        Seu aplicativo de geração de laudos ergonômicos favorito.
      </p>

      {/* Botão */}
      <button
        onClick={handleContinuar}
        style={{
          width: "100%", maxWidth: 320,
          background: "#fff",
          color: cor,
          border: "none", borderRadius: 14,
          padding: "16px 24px",
          fontSize: 16, fontWeight: 700,
          fontFamily: "Sora, sans-serif",
          cursor: "pointer",
          boxShadow: "0 6px 24px rgba(0,0,0,0.2)",
          letterSpacing: "0.01em",
        }}
      >
        Começar →
      </button>

      {/* Versão */}
      <p style={{
        marginTop: 32, fontSize: 12,
        color: "rgba(255,255,255,0.45)",
        textAlign: "center",
      }}>
        ErgoLaudo · Análise Ergonômica do Trabalho
      </p>
    </div>
  );
}

function AppLaudo() {
  const [showSplash, setShowSplash] = useState(true);
  const [laudo, setLaudo] = useState(emptyLaudo());
  const [tela, setTela] = useState("menu");
  const [abaAtiva, setAbaAtiva] = useState("laudo"); // "laudo" | "config"
  const [tema, setTema] = useState({ cor: "#0A2647", modoEscuro: false });

  // Carrega tema salvo
  useEffect(() => {
    (async () => {
      try {
        const result = (() => { const v = localStorage.getItem("ergolaudo-tema"); return v ? { value: v } : null })();
        if (result?.value) setTema(JSON.parse(result.value));
      } catch {}
    })();
  }, []);

  const salvarTema = async (novoTema) => {
    setTema(novoTema);
    try { localStorage.setItem("ergolaudo-tema", JSON.stringify(novoTema)); } catch {}
  };
  const [perfil, setPerfil] = useState({ nome: "", email: "", isAdmin: false });

  // Carrega perfil salvo
  useEffect(() => {
    (async () => {
      try {
        const result = (() => { const v = localStorage.getItem("ergolaudo-perfil"); return v ? { value: v } : null })();
        if (result?.value) {
          const p = JSON.parse(result.value);
          setPerfil(p);
        }
      } catch {}
    })();
  }, []);

  const salvarPerfil = async (novoPerfil) => {
    setPerfil(novoPerfil);
    try {
      localStorage.setItem("ergolaudo-perfil", JSON.stringify(novoPerfil));
    } catch {}
  };

  // ✅ ADICIONADO: Email via variável de ambiente com fallback seguro
  const ADMIN_EMAIL = "admin@ergolaudo.local";
  
  if (!"") {
    console.warn("⚠️ REACT_APP_ADMIN_EMAIL não configurada. Usando fallback: admin@ergolaudo.local");
  }
  const usuarioAtual = { ...perfil, isAdmin: perfil.email?.toLowerCase().trim() === ADMIN_EMAIL };
  const [cargoAbertoId, setCargoAbertoId] = useState(null);
  const [mostrarModalGeracao, setMostrarModalGeracao] = useState(false);
  const [registros, setRegistros] = useState([]);

  // In the real app this comes from Firebase Auth (your account flagged isAdmin: true).
  // Hardcoded here only so this standalone preview can demonstrate both views.

  useEffect(() => {
    (async () => {
      try {
        const result = localStorage.getItem("ergolaudo-registros-gerados", true);
        if (result?.value) setRegistros(JSON.parse(result.value));
      } catch {
        // No shared history yet — starts empty, that's expected on first use.
      }
    })();
  }, []);

  const persistirRegistros = async (novaLista) => {
    setRegistros(novaLista);
    try {
      localStorage.setItem("ergolaudo-registros-gerados", JSON.stringify(novaLista), true);
    } catch {
      // Best-effort; the in-memory list still works for this session.
    }
  };

  const irParaMenu = () => setTela("menu");

  // ---------- Section setters (one per top-level slice of `laudo`) ----------

  const setDadosGerais = (updater) =>
    setLaudo((l) => ({
      ...l,
      dadosGerais: typeof updater === "function" ? updater(l.dadosGerais) : updater,
    }));

  const setPopulacao = (updater) =>
    setLaudo((l) => ({
      ...l,
      populacao: typeof updater === "function" ? updater(l.populacao) : updater,
    }));

  const setPlanoAcao = (updater) =>
    setLaudo((l) => ({
      ...l,
      planoAcao: typeof updater === "function" ? updater(l.planoAcao) : updater,
    }));

  const setAnexos = (updater) =>
    setLaudo((l) => ({
      ...l,
      anexos: typeof updater === "function" ? updater(l.anexos) : updater,
    }));

  // ---------- Cargo flow (mirrors the previously-validated App.jsx) ----------

  const handleAdicionarCargoVazio = () => {
    const novo = { id: crypto.randomUUID(), ...emptyCargo(), complete: false };
    setLaudo((l) => ({ ...l, cargos: [novo, ...l.cargos] }));
    setCargoAbertoId(novo.id);
    setTela("cargoForm");
  };

  const handleConfirmarSelecaoCargos = (nomes) => {
    const novos = nomes.map((nome) => ({
      id: crypto.randomUUID(), ...emptyCargo(), nome, complete: false,
    }));
    setLaudo((l) => {
      const nomesExistentes = new Set((l.cargos || []).map((c) => c.nome));
      const semDuplicar = novos.filter((n) => !nomesExistentes.has(n.nome));
      return { ...l, cargos: [...semDuplicar, ...l.cargos] };
    });
  };

  const handleAbrirCargo = (id) => {
    setCargoAbertoId(id);
    setTela("cargoForm");
  };

  const handleExcluirCargo = (id) =>
    setLaudo((l) => ({ ...l, cargos: (l.cargos || []).filter((c) => c.id !== id) }));

  const handleToggleCargoComplete = (id) =>
    setLaudo((l) => ({
      ...l,
      cargos: (l.cargos || []).map((c) => (c.id === id ? { ...c, complete: !c.complete } : c)),
    }));

  const handleSalvarCargo = (dadosFormulario) => {
    setLaudo((l) => ({
      ...l,
      cargos: (l.cargos || []).map((c) => (c.id === cargoAbertoId ? { ...c, ...dadosFormulario, id: c.id } : c)),
    }));
    setTela("cargos");
  };

  const cargoAberto = (laudo.cargos || []).find((c) => c.id === cargoAbertoId);
  const nomesJaAdicionados = (laudo.cargos || []).map((c) => c.nome).filter(Boolean);

  // ---------- PDF export ----------
  // A geração real do PDF (via API Python/ReportLab) lê o objeto `laudo` diretamente.
  // O modal simula o fluxo e salva o registro até a integração com o backend.

  const handleGerarPdf = () => setMostrarModalGeracao(true);

  const handleConfirmarGeracao = async (valorCobrado) => {
    const novoRegistro = {
      id: crypto.randomUUID(),
      empresaNome: laudo.dadosGerais?.empresa?.razaoSocial || "Empresa sem nome",
      profissionalNome: usuarioAtual.nome,
      profissionalEmail: usuarioAtual.email,
      data: new Date().toISOString(),
      valorCobrado: valorCobrado ? valorCobrado.replace(",", ".") : "",
      laudoSnapshot: JSON.parse(JSON.stringify(laudo)), // cópia completa do laudo
    };
    await persistirRegistros([novoRegistro, ...registros]);
    setMostrarModalGeracao(false);
    // TODO: Substituir por toast/notificação visual
    // debug log removed
  };

  // ---------- Routing ----------

  const COR = tema.cor;
  const ESCURO = tema.modoEscuro;
  const BG = ESCURO ? "#0F1117" : "#F7F8FA";
  const CARD_BG = ESCURO ? "#1C2030" : "#fff";
  const TEXTO = ESCURO ? "#F0EEE6" : "#1C1F1D";
  const BORDA = ESCURO ? "#2A2D3A" : "#E5E3DC";

  // Splash screen — mostrada antes de qualquer tela
  if (showSplash) {
    return <TelaSplash cor={COR} onContinuar={() => setShowSplash(false)} />;
  }

  if (tela === "dadosGerais") {
    return <DadosGerais dados={laudo.dadosGerais} onChange={setDadosGerais} onClose={irParaMenu} />;
  }

  if (tela === "populacao") {
    return <DadosPopulacao dados={laudo.populacao} onChange={setPopulacao} onClose={irParaMenu} />;
  }

  if (tela === "planoAcao") {
    return <PlanoAcao dados={laudo.planoAcao} onChange={setPlanoAcao} onClose={irParaMenu} cargos={laudo.cargos} />;
  }

  if (tela === "anexos") {
    return <Anexos dados={laudo.anexos} onChange={setAnexos} onClose={irParaMenu} />;
  }

  if (tela === "selecaoCargos") {
    return (
      <SelecaoCargos
        onConfirmar={handleConfirmarSelecaoCargos}
        onVoltar={() => setTela("cargos")}
        jaAdicionados={nomesJaAdicionados}
        onRemover={(nome) => setLaudo((l) => ({ ...l, cargos: (l.cargos || []).filter((c) => c.nome !== nome) }))}
      />
    );
  }

  if (tela === "cargoForm" && cargoAberto) {
    return (
      <CargoForm
        key={cargoAberto.id}
        initialCargo={cargoAberto}
        onSave={handleSalvarCargo}
        onClose={() => setTela("cargos")}
      />
    );
  }

  if (tela === "cargos") {
    return (
      <CargoList
        cargos={laudo.cargos}
        onAdd={handleAdicionarCargoVazio}
        onOpen={handleAbrirCargo}
        onDelete={handleExcluirCargo}
        onToggleComplete={handleToggleCargoComplete}
        onSelecionarCargos={() => setTela("selecaoCargos")}
        onClose={irParaMenu}
      />
    );
  }

  if (tela === "historico") {
    const registrosComAcao = (registros || []).map((r) => ({
      ...r,
      onAbrirArquivo: () => {
        // TODO: Implementar busca real de arquivo em Firebase Storage
        console.warn("⚠️ Funcionalidade de download ainda não implementada. Firebase Storage necessário.");
        // Placeholder: poderia redirecionar para uma tela de download com mensagem amigável
      },
    }));
    const meusRegistros = registrosComAcao.filter((r) => r.profissionalEmail === usuarioAtual.email);
    return (
      <Historico
        onClose={irParaMenu}
        registros={usuarioAtual.isAdmin ? registrosComAcao : meusRegistros}
        isAdmin={usuarioAtual.isAdmin}
      />
    );
  }


  const CORES_DISPONIVEIS = [
    { cor: "#0A2647", nome: "Azul Noite" },
    { cor: "#1B4332", nome: "Verde Floresta" },
    { cor: "#7A1F3D", nome: "Vinho" },
    { cor: "#5B3E9C", nome: "Roxo" },
    { cor: "#B5451B", nome: "Terracota" },
    { cor: "#1A5276", nome: "Azul Oceano" },
  ];

  const NavBar = () => (
    <div style={{
      position: "fixed", bottom: 0, left: "50%", transform: "translateX(-50%)",
      width: "100%", maxWidth: 640,
      background: CARD_BG, borderTop: `1px solid ${BORDA}`,
      display: "flex", zIndex: 100,
    }}>
      {[
        { key: "laudo", label: "Laudo", Icon: ClipboardList },
        { key: "config", label: "Configurações", Icon: Settings },
      ].map(({ key, label, Icon }) => (
        <button key={key}
          onClick={() => { setAbaAtiva(key); if (key === "laudo") setTela("menu"); }}
          style={{
            flex: 1, display: "flex", flexDirection: "column",
            alignItems: "center", gap: 3, padding: "10px 0 14px",
            background: "none", border: "none", cursor: "pointer",
            fontFamily: "Inter, sans-serif", position: "relative",
          }}>
          <Icon size={21} color={abaAtiva === key ? COR : ESCURO ? "#6B7280" : "#9B9A90"} strokeWidth={abaAtiva === key ? 2.5 : 1.8} />
          <span style={{ fontSize: 11, fontWeight: 600, color: abaAtiva === key ? COR : ESCURO ? "#6B7280" : "#9B9A90" }}>{label}</span>
          {abaAtiva === key && (
            <div style={{ position: "absolute", bottom: 0, width: 36, height: 3, background: COR, borderRadius: 2 }} />
          )}
        </button>
      ))}
    </div>
  );

  if (abaAtiva === "config") {
    const iniciais = perfil.nome
      ? (perfil.nome || "").split(" ").filter(Boolean).slice(0, 2).map(n => n[0]).join("").toUpperCase()
      : "?";
    // ✅ ADICIONADO: Verificação de admin via variável de ambiente
    const ADMIN_EMAIL = "admin@ergolaudo.local";
    const isAdmin = perfil.email?.toLowerCase().trim() === ADMIN_EMAIL.toLowerCase();

    const SectionLabel = ({ children }) => (
      <p style={{
        fontFamily: "Sora, sans-serif", fontSize: 10.5, fontWeight: 700,
        letterSpacing: "0.08em", textTransform: "uppercase",
        color: ESCURO ? "#6B7280" : "#9B9A90", margin: "24px 0 8px 4px",
      }}>{children}</p>
    );

    const Card = ({ children, style = {} }) => (
      <div style={{
        background: CARD_BG,
        border: `1px solid ${BORDA}`,
        borderRadius: 14,
        overflow: "hidden",
        boxShadow: ESCURO ? "none" : "0 1px 3px rgba(0,0,0,0.06)",
        ...style,
      }}>{children}</div>
    );

    const Row = ({ icon, label, right, onClick, danger, last }) => (
      <button onClick={onClick} style={{
        width: "100%", display: "flex", alignItems: "center", gap: 12,
        padding: "14px 16px", background: "none", border: "none",
        borderBottom: last ? "none" : `1px solid ${BORDA}`,
        cursor: onClick ? "pointer" : "default", fontFamily: "Inter, sans-serif",
        textAlign: "left",
      }}>
        <span style={{
          width: 34, height: 34, borderRadius: 9, flexShrink: 0,
          background: danger ? "#FBE8E6" : ESCURO ? "#252836" : "#F0EEE6",
          display: "flex", alignItems: "center", justifyContent: "center",
          fontSize: 17,
        }}>{icon}</span>
        <span style={{ flex: 1, fontSize: 14, fontWeight: 500, color: danger ? "#C0392B" : TEXTO }}>{label}</span>
        {right && <span style={{ fontSize: 13, color: "#9B9A90", flexShrink: 0 }}>{right}</span>}
        {onClick && !right && <span style={{ color: "#C8C6BE", fontSize: 16 }}>›</span>}
      </button>
    );

    return (
      <div style={{ minHeight: "100vh", background: BG, fontFamily: "Inter, sans-serif", color: TEXTO, paddingBottom: 90 }}>

        {/* Hero — avatar + nome */}
        <div style={{
          background: ESCURO
            ? "linear-gradient(160deg, #1A1D2E 0%, #252836 100%)"
            : `linear-gradient(160deg, ${COR} 0%, ${COR}CC 100%)`,
          padding: "48px 20px 32px", textAlign: "center",
        }}>
          <div style={{
            width: 72, height: 72, borderRadius: "50%",
            background: ESCURO ? "rgba(255,255,255,0.08)" : "rgba(255,255,255,0.18)",
            border: ESCURO ? "2.5px solid rgba(255,255,255,0.2)" : "2.5px solid rgba(255,255,255,0.4)",
            display: "flex", alignItems: "center", justifyContent: "center",
            margin: "0 auto 12px",
            fontFamily: "Sora, sans-serif", fontSize: 26, fontWeight: 700, color: "#fff",
          }}>{iniciais}</div>
          <h2 style={{ fontSize: 18, fontWeight: 700, color: "#fff", margin: "0 0 4px" }}>
            {perfil.nome || "Seu nome aqui"}
          </h2>
          <p style={{ fontSize: 13, color: "rgba(255,255,255,0.75)", margin: 0 }}>
            {perfil.crefito ? `CREFITO ${perfil.crefito}` : "Configure seu perfil abaixo"}
          </p>
          {isAdmin && (
            <div style={{
              display: "inline-flex", alignItems: "center", gap: 5,
              marginTop: 10, padding: "4px 12px",
              background: "rgba(255,255,255,0.18)", borderRadius: 20,
              fontSize: 11.5, fontWeight: 700, color: "#fff", letterSpacing: "0.04em",
            }}>
              ADMINISTRADOR
            </div>
          )}
        </div>

        <div style={{ maxWidth: 640, margin: "0 auto", padding: "0 16px" }}>

          {/* Perfil */}
          <SectionLabel>Perfil</SectionLabel>
          <Card>
            {[
              { label: "Nome completo", key: "nome", placeholder: "Ex.: Rafael Henrique Souza", Icon: User },
              { label: "E-mail profissional", key: "email", placeholder: "Ex: rafael@consultoria.com.br", icon: "✉️" },
              { label: "CREFITO", key: "crefito", placeholder: "Ex.: 123456-F ou 123456-TO", Icon: CreditCard, isCrefito: true },
            ].map(({ label, key, placeholder, Icon, isCrefito }, i, arr) => (
              <div key={key} style={{ padding: "12px 16px", borderBottom: i < arr.length - 1 ? `1px solid ${BORDA}` : "none" }}>
                <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 6 }}>
                  <span style={{ display: "flex", alignItems: "center", color: ESCURO ? "#9B9A90" : "#44473F" }}>{Icon && <Icon size={15} />}</span>
                  <span style={{ fontSize: 12, fontWeight: 600, color: ESCURO ? "#6B7280" : "#9B9A90" }}>{label}</span>
                </div>
                {isCrefito ? (
                  <div>
                    <div style={{ position: "relative" }}>
                      <input
                        style={{
                          fontFamily: "Inter, sans-serif", fontSize: 14.5,
                          padding: "9px 40px 9px 12px",
                          border: `1.5px solid ${
                            validarCREFITO(perfil[key]) === false ? "#C0392B"
                            : validarCREFITO(perfil[key]) === true ? "#2E7D4F"
                            : BORDA}`,
                          borderRadius: 8,
                          background: validarCREFITO(perfil[key]) === false ? "#FBE8E6"
                            : validarCREFITO(perfil[key]) === true ? "#F0FAF4"
                            : ESCURO ? "#252836" : "#F7F8FA",
                          color: TEXTO, width: "100%",
                        }}
                        value={perfil[key] || ""}
                        onChange={(e) => setPerfil((p) => ({ ...p, [key]: maskCREFITO(e.target.value) }))}
                        placeholder={placeholder}
                        autoCapitalize="characters"
                      />
                      {validarCREFITO(perfil[key]) !== null && (
                        <span style={{ position: "absolute", right: 12, top: "50%", transform: "translateY(-50%)", fontSize: 16 }}>
                          {validarCREFITO(perfil[key]) ? <Check size={15} strokeWidth={3} /> : <X size={15} strokeWidth={3} />}
                        </span>
                      )}
                    </div>
                    {validarCREFITO(perfil[key]) === false && (
                      <p style={{ fontSize: 12, color: "#C0392B", margin: "4px 0 0" }}>
                        Use: 123456-F (Fisioterapeuta) ou 123456-TO (Terapeuta Ocupacional)
                      </p>
                    )}
                    {validarCREFITO(perfil[key]) === true && (
                      <p style={{ fontSize: 12, color: "#2E7D4F", margin: "4px 0 0" }}>
                        Válido —{" "}
                        <a
                          href={`https://coffito.gov.br/nsite/?page_id=2338&numero=${(perfil[key]||"").replace(/[^0-9]/g,"")}`}
                          target="_blank" rel="noopener noreferrer"
                          style={{ color: "#2E7D4F", fontWeight: 700, textDecoration: "underline" }}
                        >
                          Verificar no COFFITO ↗
                        </a>
                      </p>
                    )}
                    {validarCREFITO(perfil[key]) === null && (
                      <p style={{ fontSize: 12, color: "#9B9A90", margin: "4px 0 0" }}>
                        Formato: 123456-F ou 123456-TO
                      </p>
                    )}
                  </div>
                ) : (
                  <input
                    style={{
                      fontFamily: "Inter, sans-serif", fontSize: 14.5,
                      padding: "9px 12px", border: `1px solid ${BORDA}`,
                      borderRadius: 8, background: ESCURO ? "#252836" : "#F7F8FA",
                      color: TEXTO, width: "100%",
                    }}
                    value={perfil[key] || ""}
                    onChange={(e) => setPerfil((p) => ({ ...p, [key]: e.target.value }))}
                    placeholder={placeholder}
                  />
                )}
              </div>
            ))}
            <div style={{ padding: "12px 16px" }}>
              <button onClick={() => salvarPerfil(perfil)} style={{
                width: "100%", background: COR, color: "#fff", border: "none",
                borderRadius: 10, padding: "13px", fontSize: 14.5, fontWeight: 700,
                fontFamily: "Inter, sans-serif", cursor: "pointer",
                boxShadow: `0 4px 12px ${COR}55`,
              }}>
                Salvar perfil
              </button>
            </div>
          </Card>

          {/* Aparência */}
          <SectionLabel>Aparência</SectionLabel>
          <Card>
            {/* Toggle modo escuro */}
            <div style={{ padding: "14px 16px", display: "flex", alignItems: "center", justifyContent: "space-between", borderBottom: `1px solid ${BORDA}` }}>
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                <span style={{ width: 34, height: 34, borderRadius: 9, background: ESCURO ? "#252836" : "#F0EEE6", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 17 }}>
                  {ESCURO ? <Moon size={18} /> : <Sun size={18} />}
                </span>
                <div>
                  <p style={{ fontSize: 14, fontWeight: 600, color: TEXTO, margin: 0 }}>Modo Escuro</p>
                  <p style={{ fontSize: 12, color: "#9B9A90", margin: 0 }}>{ESCURO ? "Ativado" : "Desativado"}</p>
                </div>
              </div>
              <button onClick={() => salvarTema({ ...tema, modoEscuro: !ESCURO })} style={{
                width: 48, height: 28, borderRadius: 14, border: "none", cursor: "pointer",
                background: ESCURO ? COR : "#D8D6CD",
                position: "relative", transition: "background 0.2s", flexShrink: 0,
              }}>
                <div style={{
                  position: "absolute", top: 3,
                  left: ESCURO ? 23 : 3,
                  width: 22, height: 22, borderRadius: "50%",
                  background: "#fff",
                  boxShadow: "0 1px 3px rgba(0,0,0,0.3)",
                  transition: "left 0.2s",
                }} />
              </button>
            </div>

            {/* Cor do app */}
            <div style={{ padding: "14px 16px" }}>
              <p style={{ fontSize: 13, fontWeight: 600, color: TEXTO, margin: "0 0 12px" }}>Cor do aplicativo</p>
              <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
                {CORES_DISPONIVEIS.map(({ cor, nome }) => (
                  <button key={cor} onClick={() => salvarTema({ ...tema, cor })}
                    title={nome}
                    style={{
                      width: 40, height: 40, borderRadius: "50%",
                      background: cor, border: "none", cursor: "pointer",
                      outline: tema.cor === cor ? `3px solid ${cor}` : "3px solid transparent",
                      outlineOffset: 3,
                      boxShadow: tema.cor === cor ? `0 0 0 6px ${cor}22` : "none",
                      transition: "all 0.15s",
                      position: "relative",
                    }}>
                    {tema.cor === cor && (
                      <span style={{ color: "#fff", fontSize: 16, fontWeight: 700, lineHeight: "40px" }}>✓</span>
                    )}
                  </button>
                ))}
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 10 }}>
                <div style={{ width: 14, height: 14, borderRadius: "50%", background: COR, flexShrink: 0 }} />
                <span style={{ fontSize: 12, color: "#9B9A90" }}>
                  {CORES_DISPONIVEIS.find(c => c.cor === COR)?.nome || "Personalizada"}
                </span>
              </div>
            </div>
          </Card>


          {/* Laudos gerados */}
          <SectionLabel>Laudos Gerados ({(registros?.length || 0)})</SectionLabel>
          <Card>
            {(registros?.length || 0) === 0 ? (
              <div style={{ padding: "32px 16px", textAlign: "center" }}>
                <div style={{ marginBottom: 12, color: ESCURO ? "#3A3D4A" : "#D8D6CD" }}><Folder size={44} strokeWidth={1.2} /></div>
                <p style={{ fontSize: 13, color: "#9B9A90", margin: 0, lineHeight: 1.5 }}>
                  Nenhum laudo gerado ainda.<br />Gere seu primeiro laudo pela aba Laudo.
                </p>
              </div>
            ) : (registros || []).map((r, idx) => (
              <div key={r.id} style={{
                padding: "14px 16px",
                borderBottom: idx < (registros?.length || 1) - 1 ? `1px solid ${BORDA}` : "none",
                display: "flex", alignItems: "center", gap: 12,
              }}>
                <div style={{
                  width: 40, height: 40, borderRadius: 10, flexShrink: 0,
                  background: `${COR}18`,
                  display: "flex", alignItems: "center", justifyContent: "center",
                  fontSize: 18,
                }}><File size={20} strokeWidth={1.5} /></div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <p style={{ fontSize: 14, fontWeight: 600, color: TEXTO, margin: "0 0 2px", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                    {r.empresaNome}
                  </p>
                  <p style={{ fontSize: 12, color: "#9B9A90", margin: 0 }}>
                    {new Date(r.data).toLocaleDateString("pt-BR", { day: "2-digit", month: "short", year: "numeric" })}
                    {r.profissionalNome ? ` · ${(r.profissionalNome || "").split(" ")[0] || r.profissionalNome}` : ""}
                  </p>
                </div>
                {r.laudoSnapshot && (
                  <button
                    onClick={() => { setLaudo(r.laudoSnapshot); setAbaAtiva("laudo"); setTela("menu"); }}
                    style={{
                      flexShrink: 0, background: `${COR}15`, color: COR,
                      border: `1.5px solid ${COR}40`, borderRadius: 8,
                      padding: "7px 12px", fontSize: 12, fontWeight: 700,
                      cursor: "pointer", fontFamily: "Inter, sans-serif",
                    }}>
                    Reabrir
                  </button>
                )}
              </div>
            ))}
          </Card>

          <div style={{ height: 16 }} />
        </div>
        <NavBar />
        </div>
    );
  }

  return (
    <>
      <MenuPrincipal
        laudo={laudo}
        onAbrirSecao={(key) => setTela(key === "cargos" ? "cargos" : key)}
        onGerarPdf={handleGerarPdf}
        onAbrirHistorico={() => setTela("historico")}
        onAbrirPerfil={() => setAbaAtiva("config")}
        nomeProfissional={perfil.nome}
        registrosCount={(registros?.length || 0)}
        corTema={COR}
        escuroTema={ESCURO}
      />
      {mostrarModalGeracao && (
        <ConfirmarGeracaoModal
          empresaNome={laudo.dadosGerais?.empresa?.razaoSocial}
          onConfirm={handleConfirmarGeracao}
          onCancel={() => setMostrarModalGeracao(false)}
        />
      )}
      <NavBar />
    </>
  );
}


export default AppLaudo;
